     3→/// <summary>
     4→/// Core service that applies retention policies to a collection of artifacts
     5→/// and produces a <see cref="DeletionPlan"/> describing what to delete.
     6→///
     7→/// Policy application order (most permissive to most restrictive):
     8→///   1. MaxAgeDays          — hard age cutoff, always applied first
     9→///   2. KeepLatestNPerWorkflow — per-workflow cap, applied to age-survivors
    10→///   3. MaxTotalSizeBytes   — global size cap, oldest evicted last
    11→///
    12→/// This order ensures that old artifacts are removed before size trimming,
    13→/// so size eviction preferentially removes the oldest of the "still valid" artifacts.
    14→/// </summary>
    15→public class ArtifactCleanupService
    16→{
    17→    /// <summary>
    18→    /// Applies the retention <paramref name="policy"/> to <paramref name="artifacts"/>
    19→    /// and returns a <see cref="DeletionPlan"/>.
    20→    /// </summary>
    21→    /// <param name="artifacts">All artifacts to evaluate.</param>
    22→    /// <param name="policy">The retention rules to apply.</param>
    23→    /// <param name="referenceTime">
    24→    ///   The "now" used for age calculations.
    25→    ///   Pass a fixed value in tests to ensure determinism.
    26→    /// </param>
    27→    /// <param name="dryRun">
    28→    ///   When <c>true</c> the plan is computed but no real actions occur.
    29→    ///   The <see cref="DeletionPlan.IsDryRun"/> flag is set accordingly.
    30→    /// </param>
    31→    public DeletionPlan ApplyPolicies(
    32→        IEnumerable<Artifact> artifacts,
    33→        RetentionPolicy policy,
    34→        DateTimeOffset? referenceTime = null,
    35→        bool dryRun = false)
    36→    {
    37→        var now = referenceTime ?? DateTimeOffset.UtcNow;
    38→        var toDelete = new HashSet<Artifact>();
    39→        var candidates = artifacts.ToList();
    40→
    41→        // --- Step 1: MaxAgeDays ---
    42→        // Artifacts older than MaxAgeDays days are unconditionally deleted.
    43→        if (policy.MaxAgeDays.HasValue)
    44→        {
    45→            var cutoff = now.AddDays(-policy.MaxAgeDays.Value);
    46→            foreach (var a in candidates.Where(a => a.CreatedAt < cutoff))
    47→                toDelete.Add(a);
    48→        }
    49→
    50→        // Work with survivors after age filter
    51→        var survivors = candidates.Where(a => !toDelete.Contains(a)).ToList();
    52→
    53→        // --- Step 2: KeepLatestNPerWorkflow ---
    54→        // Within each workflow run ID, keep only the N most-recently-created artifacts.
    55→        // Older ones beyond the cap are evicted.
    56→        if (policy.KeepLatestNPerWorkflow.HasValue)
    57→        {
    58→            var n = policy.KeepLatestNPerWorkflow.Value;
    59→            // Group survivors by WorkflowRunId, then within each group sort by CreatedAt desc,
    60→            // mark everything past position N for deletion.
    61→            foreach (var group in survivors.GroupBy(a => a.WorkflowRunId))
    62→            {
    63→                var ordered = group.OrderByDescending(a => a.CreatedAt).ToList();
    64→                foreach (var a in ordered.Skip(n))
    65→                    toDelete.Add(a);
    66→            }
    67→        }
    68→
    69→        // Recompute survivors after the per-workflow cap
    70→        survivors = candidates.Where(a => !toDelete.Contains(a)).ToList();
    71→
    72→        // --- Step 3: MaxTotalSizeBytes ---
    73→        // Evict oldest artifacts until total retained size fits within the limit.
    74→        if (policy.MaxTotalSizeBytes.HasValue)
    75→        {
    76→            var limit = policy.MaxTotalSizeBytes.Value;
    77→            // Sort survivors oldest-first so we evict old ones preferentially
    78→            var byAge = survivors.OrderBy(a => a.CreatedAt).ToList();
    79→            long totalSize = byAge.Sum(a => a.SizeBytes);
    80→
    81→            foreach (var a in byAge)
    82→            {
    83→                if (totalSize <= limit) break;
    84→                toDelete.Add(a);
    85→                totalSize -= a.SizeBytes;
    86→            }
    87→        }
    88→
    89→        var finalRetained = candidates.Where(a => !toDelete.Contains(a)).ToList();
    90→        return new DeletionPlan(toDelete.ToList(), finalRetained, isDryRun: dryRun);
    91→    }
    92→}
